// Domain Availability Check
// Reads the operator-selected name from context and generates simulated
// domain availability results across common TLDs.
// In production, replace this with Domainr API, Namecheap API, or similar.
const body = $input.first().json.body;
const { projectId, stageKey, executionId, subStage } = body;
const selectedName = body.context?.selectedName || 'Nexus';

const baseName = selectedName.toLowerCase().replace(/[^a-z0-9]/g, '');

const signals = [
  {
    domain: `${baseName}.com`,
    status: "taken",
    registrar: "GoDaddy",
    price: null
  },
  {
    domain: `${baseName}.io`,
    status: "premium",
    registrar: "Namecheap",
    price: "$2,495"
  },
  {
    domain: `${baseName}.dev`,
    status: "available",
    registrar: "Google Domains",
    price: "$12/yr"
  },
  {
    domain: `${baseName}.co`,
    status: "taken",
    registrar: "Hover",
    price: null
  },
  {
    domain: `${baseName}.app`,
    status: "available",
    registrar: "Google Domains",
    price: "$14/yr"
  },
  {
    domain: `${baseName}.ai`,
    status: "premium",
    registrar: "Porkbun",
    price: "$4,999"
  }
];

return {
  json: {
    projectId,
    stageKey,
    executionId,
    subStage: subStage || 'domain_signals',
    domainResult: {
      selectedName,
      signals,
      checkedAt: new Date().toISOString(),
      disclaimer: "Domain availability is a point-in-time check. Results may change."
    }
  }
};
